<script>
function erroROI(msg){document.getElementById('erro-roi-texto').textContent=msg;document.getElementById('erro-roi').style.display='flex';document.getElementById('resultado-roi').classList.remove('show');}
function limparErroROI(){document.getElementById('erro-roi').style.display='none';}
function calcularROI(){const investimento=parseFloat(document.getElementById('roi-investimento').value);const retorno=parseFloat(document.getElementById('roi-retorno').value);limparErroROI();if(isNaN(investimento)||isNaN(retorno)||investimento<=0){erroROI('Informe investimento válido e maior que zero, além do retorno obtido.');return;}const lucro=retorno-investimento;const roi=(lucro/investimento)*100;document.getElementById('roi-percentual').textContent=fmtNum(roi,2)+'%';document.getElementById('roi-lucro').textContent='R$ '+fmtBRL(lucro);document.getElementById('roi-detalhe').textContent='O cálculo compara lucro líquido com o valor investido.';showResult('resultado-roi');}
function limparROI(){document.getElementById('roi-investimento').value='';document.getElementById('roi-retorno').value='';document.getElementById('resultado-roi').classList.remove('show');limparErroROI();}
function copiarROI(button){if(!document.getElementById('resultado-roi').classList.contains('show')){erroROI('Calcule o ROI antes de copiar o resultado.');return;}copyToClipboard('ROI: '+document.getElementById('roi-percentual').textContent+'\nLucro: '+document.getElementById('roi-lucro').textContent,button);}
</script>
